package com.example

import software.amazon.lastmile.kotlin.inject.anvil.ContributesBinding
import me.tatarka.inject.annotations.Inject

@Inject
@ContributesBinding(Unit::class)
class Impl

package com.example

import me.tatarka.inject.annotations.Component
import me.tatarka.inject.annotations.Inject
import me.tatarka.inject.annotations.Provides
import software.amazon.lastmile.kotlin.inject.anvil.AppScope
import software.amazon.lastmile.kotlin.inject.anvil.ContributesTo
import software.amazon.lastmile.kotlin.inject.anvil.MergeComponent
import software.amazon.lastmile.kotlin.inject.anvil.SingleIn

interface Base

@Inject
@SingleIn(AppScope::class)
class Impl : Base {
    @ContributesTo(AppScope::class)
    interface Component {
        @Provides fun provideImpl(impl: Impl): Base = impl
        val string: String
    }
}

@ContributesTo(AppScope::class)
interface StringComponent {
    @Provides fun provideString(): String = "abc"
}

@Component
@MergeComponent(AppScope::class)
@SingleIn(AppScope::class)
abstract class ComponentInterface : ComponentInterfaceMerged {
    abstract val base: Base
}

package com.example

import software.amazon.lastmile.kotlin.inject.anvil.ContributesSubcomponent
import software.amazon.lastmile.kotlin.inject.anvil.SingleIn

@ContributesSubcomponent(Unit::class)
@SingleIn(Unit::class)
interface SubcomponentInterface {
    @ContributesSubcomponent.Factory(String::class)
    interface Factory {
        fun createSubcomponentInterface(): SubcomponentInterface
    }
}

package com.example

import software.amazon.lastmile.kotlin.inject.anvil.ContributesSubcomponent
import software.amazon.lastmile.kotlin.inject.anvil.SingleIn

@ContributesSubcomponent(Unit::class)
@SingleIn(Unit::class)
abstract class OtherComponent {
    @ContributesSubcomponent.Factory(Unit::class)
    interface Parent {
        fun otherComponent(stringArg: String, intArg: Int): OtherComponent
    }
}

package com.example

